async function claimAutoAccount(productId, orderId) {
  const { data: accountRow, error: selectError } = await supabase
    .from('product_accounts')
    .select('id,account_data')
    .eq('product_id', productId)
    .eq('is_used', false)
    .order('created_at', { ascending: true })
    .limit(1)
    .maybeSingle();

  if (selectError) {
    throw selectError;
  }

  if (!accountRow) {
    return null;
  }

  const { data: lockedRow, error: lockError } = await supabase
    .from('product_accounts')
    .update({
      is_used: true,
      used_order_id: orderId,
      used_at: new Date().toISOString(),
    })
    .eq('id', accountRow.id)
    .eq('is_used', false)
    .select('id,account_data')
    .maybeSingle();

  if (lockError) {
    throw lockError;
  }

  return lockedRow || null;
}

async function getUserTelegramIdsByCategory(categoryId) {
  const { data: products, error: productsError } = await supabase
    .from('products')
    .select('id')
    .eq('category_id', categoryId)
    .limit(5000);

  if (productsError) {
    throw productsError;
  }

  const productIds = (products || []).map((row) => row.id).filter(Boolean);
  if (productIds.length === 0) {
    return [];
  }

  const orderIdSet = new Set();
  for (const productChunk of chunkArray(productIds, 200)) {
    const { data: items, error: itemsError } = await supabase
      .from('order_items')
      .select('order_id')
      .in('product_id', productChunk)
      .limit(5000);

    if (itemsError) {
      throw itemsError;
    }

    for (const row of items || []) {
      if (row.order_id) {
        orderIdSet.add(row.order_id);
      }
    }
  }

  const orderIds = [...orderIdSet];
  if (orderIds.length === 0) {
    return [];
  }

  const userIdSet = new Set();
  for (const orderChunk of chunkArray(orderIds, 200)) {
    const { data: orders, error: ordersError } = await supabase
      .from('orders')
      .select('user_id')
      .in('id', orderChunk)
      .limit(5000);

    if (ordersError) {
      throw ordersError;
    }

    for (const row of orders || []) {
      if (row.user_id) {
        userIdSet.add(row.user_id);
      }
    }
  }

  const userIds = [...userIdSet];
  if (userIds.length === 0) {
    return [];
  }

  const telegramIdSet = new Set();
  for (const userChunk of chunkArray(userIds, 200)) {
    const { data: users, error: usersError } = await supabase
      .from('users')
      .select('telegram_id')
      .in('id', userChunk)
      .not('telegram_id', 'is', null)
      .limit(5000);

    if (usersError) {
      throw usersError;
    }

    for (const row of users || []) {
      const tg = Number(row.telegram_id);
      if (Number.isInteger(tg)) {
        telegramIdSet.add(tg);
      }
    }
  }

  return [...telegramIdSet];
}

async function createSingleItemOrder(userId, product) {
  const total = Number(product.price || 0);

  const { data: order, error: orderError } = await supabase
    .from('orders')
    .insert({
      user_id: userId,
      status: 'confirmed',
      total_amount: total,
      currency: product.currency || 'VND',
    })
    .select('id,status,total_amount,currency')
    .single();

  if (orderError) {
    throw orderError;
  }

  const { error: itemError } = await supabase
    .from('order_items')
    .insert({
      order_id: order.id,
      product_id: product.id,
      unit_price: total,
      quantity: 1,
      total_price: total,
    });

  if (itemError) {
    throw itemError;
  }

  if (typeof product.stock_quantity === 'number') {
    const { error: stockError } = await supabase
      .from('products')
      .update({ stock_quantity: Math.max(product.stock_quantity - 1, 0) })
      .eq('id', product.id);

    if (stockError) {
      throw stockError;
    }
  }

  await supabase.from('order_history').insert({
    order_id: order.id,
    changed_by: userId,
    status: 'confirmed',
    comment: 'Order created from Telegram bot',
  });

  return order;
}

async function notifyAdminsNewOrder(orderId, total, currency) {
  const adminIds = [...runtimeAdminIds].map((id) => Number(id)).filter(Number.isInteger);
  if (adminIds.length === 0) {
    return;
  }

  const message = `Don moi #${orderId}\\nTong tien: ${total} ${currency}`;
  for (const telegramId of adminIds) {
    try {
      await bot.telegram.sendMessage(telegramId, message);
    } catch (error) {
      // Ignore failed admin notifications to keep order flow responsive.
    }
  }
}

