function calcTierPrice(basePrice, ratio) {
  const numeric = Number(basePrice || 0);
  return Math.max(Math.round(numeric * ratio), 0);
}

function buildProductDetailPanel(locale, product) {
  const box = '\uD83D\uDCE6';
  const money = '\uD83D\uDCB0';
  const chart = '\uD83D\uDCC9';
  const stockText = Number.isFinite(Number(product.stock_quantity)) ? Number(product.stock_quantity) : '-';
  const p5 = calcTierPrice(product.price, 0.875);
  const p10 = calcTierPrice(product.price, 0.8);

  if (locale === 'en') {
    return [
      `${box} ${product.name}`,
      `${money} Price: ${formatDong(product.price)}`,
      `${box} Stock: ${stockText}`,
      `${chart} Tier price:`,
      '',
      `- From 5: ${formatDong(p5)}`,
      `- From 10: ${formatDong(p10)}`,
      '',
      'Choose payment method:',
    ].join('\n');
  }

  return [
    `${box} ${product.name}`,
    `${money} Giá: ${formatDong(product.price)}`,
    `${box} Còn: ${stockText}`,
    `${chart} Giá theo SL:`,
    '',
    `- Từ 5: ${formatDong(p5)}`,
    `- Từ 10: ${formatDong(p10)}`,
    '',
    'Chọn phương thức thanh toán:',
  ].join('\n');
}

function buildCataloguePrompt(locale) {
  const point = '\uD83D\uDC49';
  return locale === 'en'
    ? `${point} CHOOSE A PRODUCT BELOW:`
    : `${point} CHỌN SẢN PHẨM BÊN DƯỚI:`;
}

function buildCatalogueKeyboard(products, locale) {
  const refresh = '\uD83D\uDD04';
  const trash = '\uD83D\uDDD1';
  const rows = products.map((p) => [Markup.button.callback(compactProductButtonLabel(p), `prd:${p.id}`)]);
  rows.push([
    Markup.button.callback(`${refresh} Cập nhật`, 'catalogue_refresh'),
    Markup.button.callback(`${trash} Xóa`, 'catalogue_close'),
  ]);
  return Markup.inlineKeyboard(rows);
}
async function sendCataloguePanel(ctx, locale, shouldEdit = false) {
  const products = await loadActiveProducts();
  if (products.length === 0) {
    if (shouldEdit) {
      try {
        await ctx.editMessageText(t(locale, 'emptyCatalogue'));
      } catch (error) {
        await safeReply(ctx, t(locale, 'emptyCatalogue'));
      }
      return;
    }

    await ctx.reply(t(locale, 'emptyCatalogue'));
    return;
  }

  const text = buildCataloguePrompt(locale);
  const keyboard = buildCatalogueKeyboard(products, locale);

  if (shouldEdit) {
    try {
      await ctx.editMessageText(text, keyboard);
      return;
    } catch (error) {
      await safeReply(ctx, text, keyboard);
      return;
    }
  }

  await ctx.reply(text, keyboard);
}

async function processPurchase(ctx, user, locale, product) {
  if (typeof product.stock_quantity === 'number' && product.stock_quantity <= 0) {
    await safeReply(ctx, t(locale, 'outOfStock'));
    return;
  }

  const order = await createSingleItemOrder(user.id, product);
  const message = t(locale, 'orderCreated', {
    id: order.id,
    total: order.total_amount,
    currency: order.currency || 'VND',
  });

  await ctx.reply(message);

  if (product.delivery_type === 'auto') {
    const account = await claimAutoAccount(product.id, order.id);
    if (account?.account_data) {
      await ctx.reply(
        `Tai khoan cua ban (dinh dang tk|mk|2fa):\\n${account.account_data}\\n\\nLuu y: Doi mat khau ngay sau khi nhan.`,
      );
    } else {
      await ctx.reply(
        'Tam het tai khoan auto. Vui long nhan admin de duoc cap bo sung sau khi chuyen khoan thanh cong.',
      );
    }
  } else {
    const manualNote = product.manual_contact_note
      || 'Loai khong auto. Sau khi chuyen khoan thanh cong, vui long nhan admin de nhan tai khoan.';
    await ctx.reply(manualNote);
  }

  await notifyAdminsNewOrder(order.id, order.total_amount, order.currency || 'VND');
}

function adminProductsListText(products) {
  const lines = products.map((p) => {
    const status = p.is_active ? 'active' : 'inactive';
    return `- ${p.name} | ${p.price} ${p.currency || 'VND'} | ton:${p.stock_quantity ?? '-'} | ${status}`;
  });

  return [
    'QUAN LY SAN PHAM',
    '',
    ...lines,
    '',
    'Chon san pham de sua/xoa hoac bam Them moi.',
  ].join('\n');
}

function buildAdminProductsKeyboard(products) {
  const rows = products.map((p) => {
    const icon = p.is_active ? 'ON' : 'OFF';
    const label = `[${icon}] ${String(p.name || '').slice(0, 28)}`;
    return [Markup.button.callback(label, `admprd:${p.id}`)];
  });

  rows.push([
    Markup.button.callback('Them moi', 'admin_add_product_start'),
    Markup.button.callback('Cap nhat', 'admin_products_refresh'),
  ]);
  rows.push([Markup.button.callback('Xoa panel', 'admin_products_close')]);

  return Markup.inlineKeyboard(rows);
}

function adminProductDetailText(product) {
  return [
    `SAN PHAM: ${product.name}`,
    `Gia: ${product.price} ${product.currency || 'VND'}`,
    `Ton: ${product.stock_quantity ?? '-'}`,
    `Trang thai: ${product.is_active ? 'active' : 'inactive'}`,
    '',
    'Tac vu: Sua gia, sua ton, bat/tat, xoa.',
  ].join('\n');
}

function adminProductDetailKeyboard(product) {
  const toggleTo = product.is_active ? '0' : '1';
  return Markup.inlineKeyboard([
    [Markup.button.callback(product.is_active ? 'Tat san pham' : 'Mo san pham', `prdtg:${product.id}:${toggleTo}`)],
    [
      Markup.button.callback('Sua gia', `admsetprice:${product.id}`),
      Markup.button.callback('Sua ton', `admsetstock:${product.id}`),
    ],
    [Markup.button.callback('Xoa san pham', `admdelete:${product.id}`)],
    [Markup.button.callback('Danh sach', 'admin_products_v2')],
  ]);
}

async function sendAdminProductsPanel(ctx, shouldEdit = false) {
  const products = await loadAdminProducts();
  if (products.length === 0) {
    if (shouldEdit) {
      try {
        await ctx.editMessageText('Chua co san pham.');
      } catch (error) {
        await safeReply(ctx, 'Chua co san pham.');
      }
      return;
    }
    await ctx.reply('Chua co san pham.');
    return;
  }

  const text = adminProductsListText(products);
  const keyboard = buildAdminProductsKeyboard(products);
  if (shouldEdit) {
    try {
      await ctx.editMessageText(text, keyboard);
      return;
    } catch (error) {
      await safeReply(ctx, text, keyboard);
      return;
    }
  }
  await ctx.reply(text, keyboard);
}

function setPendingAdminInput(ctx, payload) {
  pendingAdminInputs.set(String(ctx.from.id), payload);
}

function clearPendingAdminInput(ctx) {
  pendingAdminInputs.delete(String(ctx.from.id));
}

